// PASTE CONTENTS OF: workflows/n8n/code/normalizer.js
// Full source in repo — keep this node in sync
const perplexityRaw = JSON.parse($('Perplexity: Opportunity Scan').first().json.choices[0].message.content);
const gscRows = $('GSC: Top Queries').first().json.rows || [];
const gscIndex = {};
for (const row of gscRows) {
  const keyword = row.keys?.[0]?.toLowerCase();
  if (keyword) gscIndex[keyword] = { clicks: row.clicks || 0, position: row.position || 99 };
}
const opportunities = [];
for (const kw of perplexityRaw.low_competition_keywords || []) {
  const d = { very_low: 9.5, low: 7.5, medium: 5.5 }[kw.difficulty] ?? 5.0;
  const i = { commercial: 1.5, local: 1.3, transactional: 1.4, informational: 1.0 }[kw.intent] ?? 1.0;
  const seo = Math.min(10, parseFloat((d * i).toFixed(1)));
  const gsc = gscIndex[kw.keyword.toLowerCase()];
  const aeo = kw.intent === 'informational' ? 6.0 : 5.0;
  const combined = seo + aeo;
  opportunities.push({
    keyword: kw.keyword, intent: kw.intent, seo_score: seo, aeo_score: aeo,
    combined_score: combined,
    priority: combined >= 16 ? 'critical' : combined >= 12 ? 'high' : 'medium',
    recommended_action: gsc ? 'optimize' : 'create',
    source: 'perplexity_weekly_scan'
  });
}
opportunities.sort((a, b) => b.combined_score - a.combined_score);
return opportunities.filter(o => ['critical','high'].includes(o.priority)).map(o => ({ json: o }));

