// Inline stub below — use full file in production
let article;
try {
  article = JSON.parse($input.first().json.content[0].text);
} catch (e) {
  throw new Error('AEO Validator: Cannot parse Claude response — ' + e.message);
}
const html = article.article_html || '';
const issues = [];
const warnings = [];
if ((article.meta_title?.length || 0) > 60) issues.push('META_TITLE_TOO_LONG');
if (!article.h1) issues.push('H1_MISSING');
if ((html.match(/<h2/gi) || []).length < 4) issues.push('TOO_FEW_H2S');
if (!/frequently asked|faq/i.test(html)) issues.push('MISSING_FAQ_SECTION');
if (!article.faq_pairs || article.faq_pairs.length < 6) issues.push('TOO_FEW_FAQ_PAIRS');
if (!html.includes('Audio Jones')) issues.push('MISSING_AUTHOR_BLOCK');
if ((article.word_count_estimate || 0) < 800) issues.push('WORD_COUNT_TOO_LOW');
if (!/work-with-us|book.*session/i.test(html)) issues.push('MISSING_CTA');
return [{ json: { passed: issues.length === 0, issues, warnings, article } }];

